void mezcla(vector<int> v1, int n1, vector<int> v2, int n2, vector<int> &v3) {
    v3.resize(n1 + n2);
    int i = 0, j = 0, k = 0;
    while (i < n1 && j < n2) {
        if (v1[i] <= v2[j]) {
            v3[k++] = v1[i++];
        } else {
            v3[k++] = v2[j++];
        }
    }
    while (i < n1) v3[k++] = v1[i++];
    while (j < n2) v3[k++] = v2[j++];
}
